const getGames = () => catalogGames(state);
const presencePrivacy = () => ({visibility:state.settings.showStatus?(isUnder(state.user.dob,13)?'friends':'everyone'):'nobody',joinPrivacy:state.settings.invisible?'nobody':(isUnder(state.user.dob,13)&&state.settings.joinPrivacy==='everyone'?'friends':state.settings.joinPrivacy)});
const getPeople = () => {
  if(!firebaseReady||!state.cloudProfiles?.length)return allPeople();
  return state.cloudProfiles.filter(profile=>profile.id!==state.user.id&&!state.blocked.includes(profile.id)).map((profile,index)=>{
    const presence=state.cloudPresence?.[profile.id]||{state:'offline'},game=getGames().find(item=>item.id===presence.gameId);
    const joinAllowed=presence.joinPrivacy==='everyone'||(presence.joinPrivacy==='friends'&&state.friends.includes(profile.id));
    return {id:profile.id,name:profile.displayName||profile.username||'Player',username:profile.username||profile.id,status:presence.state||'offline',game:game?.title,gameId:presence.gameId,sessionId:presence.sessionId,joinable:Boolean(presence.joinable&&joinAllowed&&!state.settings.invisible),avatar:profile.avatar||['#FF8B62','#5FCCA6','#DD7DFF','#58A9E8','#D7C65D'][index%5],profilePublic:true,showFriends:profile.showFriends!==false,publishedGames:(state.cloudGames||[]).filter(item=>item.ownerId===profile.id&&item.status==='published').map(item=>item.title)};
  });
};
