document.addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key==='k'){e.preventDefault();document.querySelector('#global-search')?.focus();}if(e.key==='Escape'&&modal){modal=null;render();}});
render();
if(firebaseReady) firebaseAuth.observe(async user=>{
  if(state.auth.provider==='local-demo')return;
  if(!user){cloudUnsubscribe?.();cloudUnsubscribe=null;state.auth={signedIn:false,provider:null,demoRole:null};persist();render();return;}
  state.auth={signedIn:true,provider:'firebase'};
  state.user={...state.user,id:user.id,email:user.email,emailVerified:user.emailVerified,displayName:user.displayName||state.user.displayName,role:user.role};
  // Returning accounts: rebuild local state from the cloud profile so login on
  // a fresh browser does not re-run onboarding (the trusted API would 409).
  try{const own=await firebaseData.loadOwnProfile(user.id);
    if(own?.profile?.username){state.user.username=own.profile.username;state.user.displayName=own.profile.displayName||own.profile.username;state.user.bio=own.profile.bio||state.user.bio;state.user.avatar=own.profile.avatar||state.user.avatar;state.user.onboarded=true;}
    else if(state.auth.provider==='firebase')state.user.onboarded=false;
    if(own?.identity){state.user.dob=own.identity.dateOfBirth;state.user.parentEmail=own.identity.parentEmail||'';if(own.identity.ageBand!=='U13')state.user.parentConsent=true;}
    if(own?.preferences){if(own.preferences.favorites)state.favorites=own.preferences.favorites;if(own.preferences.settings)state.settings={...state.settings,...own.preferences.settings};if(own.preferences.blocked)state.blocked=own.preferences.blocked;}
  }catch{}
  startCloudSync(user);
  persist();
  syncCloud(firebaseData.watchParentConsent(user.id,approved=>{if(approved){state.user.parentConsent=true;persist();render();}}));
  if(user.emailVerified)syncCloud(firebaseData.watchParentRequests(user.email,requests=>{
    state.parentApprovalRequests=requests;
    requests.filter(request=>request.status==='approved').forEach(request=>{
      syncCloud(firebaseData.watchParentView(request.childUid,view=>{state.parentChildViews={...(state.parentChildViews||{}),[request.childUid]:view};persist();render();}));
      syncCloud(firebaseData.watchParentControls(request.childUid,controls=>{state.parentChildControls={...(state.parentChildControls||{}),[request.childUid]:controls};persist();render();}));
    });
    persist();render();
  }));
  if(isUnder(state.user.dob,13))syncCloud(firebaseData.watchParentControls(user.id,controls=>{state.parentControls=controls;persist();render();}));
  render();
});
